var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"우읍......","JPN":"ううっ……","ENG":"Blech...","TWN":"唔……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"너무 맵슴다. 이런 걸 계속 먹다간 죽을 검다......","JPN":"辛いっす。このまま食べ続けたら死んじゃうっす……","ENG":"This is too spicy, ma'am. I will surely die if I keep eating this sort of stuff.","TWN":"好辣，再吃下去肯定會死的啊……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"거 참 말 많네. 어릴 때부터 편식하면 혼난다는 거 안 배웠어?","JPN":"うるさいわね。お家で好き嫌いしたらダメって教えてもらわなかったの？","ENG":"Quit complaining. Where are your table manners?","TWN":"你話可真多，小時候沒人教你不能挑食嗎？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L7_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"이거 정말 고문 아님까?","JPN":"これは完全に拷問っす！","ENG":"Are you sure this is not torture?","TWN":"你們這是嚴刑拷問啦！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"그럼 모네는 한마디도 안 할 검다! 메이드장님을 위해 꼬, 꼴까닥 할 검다......!","JPN":"モネはこれから一言も言わないっす！　メイド長のためなら、し、舌を噛み切ってやるっす……！","ENG":"Then you won't get a word out of Mone! I-I'm willing to lay down my life for the Chief Maid!","TWN":"莫妮不會再說一句話！我要為女僕長拋頭顱灑熱血……！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L9_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"뭐야, 꼬맹이 주제에 어디서 그런 무서운 말을 배웠어?","JPN":"ちょっと、チビのくせにそんな恐ろしいこと言うんじゃないわよ？","ENG":"Hey, kid. Where did you learn to be so serious?","TWN":"你這個小鬼，這種話也敢亂說？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L10_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L12_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L13_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"매우면 우유 줄까?","JPN":"そんなに辛いなら牛乳でも飲む？","ENG":"You want some milk to cool down the spice?","TWN":"太辣的話給你點牛奶？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L14_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"넵!","JPN":"はいっ！","ENG":"Yes, please!","TWN":"好！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L15_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"아앗?! 당했슴다!","JPN":"あ！？　喋ってしまったっす！","ENG":"Oh no! You got me!","TWN":"啊？！被騙了啦！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"푸하아. 이제 겨우 살 것 같슴다.","JPN":"ふあぁ、生き返ったっす。","ENG":"Ah... That's much better, ma'am.","TWN":"呼啊，終於能喘口氣了啦。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"마음은 알겠는데 너무 무리하지 마세요, 바보 꼬맹이 씨.","JPN":"気持ちはわかるけどあまり無理しないでね、おバカチビさん。","ENG":"I know how you feel, but don't push yourself so hard, you little clown.","TWN":"我知道你在想什麼，但不要太過了，小傻瓜。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"어차피 릴리 말대로라면 아무리 상황이 나빠져도 맨션에 들어가게 될 뿐이니까.","JPN":"リリーの話だと、状況が悪くなってもマンションに入るだけみたいだし。","ENG":"Based on what Lily said, you'll still end up in the Mansion even if things go terribly wrong.","TWN":"就如莉莉所說，最壞的情況也就是進入曼森而已。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"우으...... 모네는 메이드장님을 괴롭히는 데 가기 싫슴다......","JPN":"うう……モネはメイド長をいじめる所には行きたくないっす……","ENG":"Aw... But I don't want to go where they bullied the Chief Maid...","TWN":"額……莫妮不想去那個欺負女僕長大人的地方啦……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L24_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"대체 맨션이란 데가 뭔데 메이드장님을 괴롭히는 검까?","JPN":"メイド長をいじめるマンションという所は、いったいどんな所っすか？","ENG":"What is this Mansion anyway? Why are they picking on the Chief Maid?","TWN":"曼森到底是什麼，他們為什麼要欺負女僕長大人啦？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"뭐, 아무데나 맡겼다간 곤란해질 만한 일을 대신 해 주는 데야.","JPN":"まあ、簡単に説明すると公にできない仕事を代行する所よ。","ENG":"Well, it's a place that provides services that are unavailable anywhere else. Services that could get you in trouble.","TWN":"曼森是幫一些人處理他們難辦的事情的地方。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"곤란한 일......?","JPN":"公にできない……っすか？","ENG":"Get you in trouble?","TWN":"難辦的事……？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L27_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"독극물 테러, 납치, 청부 살인, 이것저것.","JPN":"テロ、拉致、殺人依頼などなど……","ENG":"You know, things like chemical weapon terrorism, abduction, contract killing, and so on.","TWN":"下毒搞破壞、綁架、殺人等等。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L28_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"메이드들끼리는 요리니 빨래니 청소니 점잖은 척 부르지만 말이야.","JPN":"メイド同士は料理とか洗濯とかって言い回しを使っているけどね。","ENG":"Of course, we use euphemisms like \\"cooking\\" or \\"laundry\\" amongst ourselves.","TWN":"女僕之間卻暗指這些為料理啊，洗衣服啊，打掃啊什麼的。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L29_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"무...... 무시무시하게 무서운 언니들이었지 말임다......","JPN":"と……とんでもなく恐ろしいお姉さんたちだったんすね……","ENG":"I-I didn't know you folks were this scary...","TWN":"原來是這麼可……可怕的姐姐們啦……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L30_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"그래? 내가 알기론 그 베로니카란 사람이 메이드 중에서 제일 위험하다던데?","JPN":"そう？　私が知る限りではあのベロニカって人がメイドの中で一番危険らしいよ？","ENG":"Really? As far as I know, Veronica's the most dangerous of us all.","TWN":"可怕？我怎麼聽說那個貝洛妮卡是所有女僕中最危險的人物呢？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L31_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"그럴 리 없슴다! 메이드장님은 머리에 참새가 앉아서 쉬어 갈 만큼 얌전함다!","JPN":"そんなはずないっす！　メイド長は頭の上にスズメさんが乗って一休みするくらい穏やかな方っす！","ENG":"No way, ma'am! Chief Maid is so peaceful that even a sparrow could rest on her shoulders!","TWN":"不可能！女僕長大人很善良，連小鳥都會停留在她的頭上休息啦！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L32_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"저번에는 독수리도 앉아 있었슴다!","JPN":"この前は鷲も乗ってたんっす！","ENG":"She even had an eagle perch on her the other day!","TWN":"上次連老鷹都落到她頭上呢！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"야. 그건 좀 이상하게 생각해야지. 요새 애들은 상식이란 게 없나, 정말.","JPN":"ねえ、それはちょっとおかしいと思うべきじゃないの。まったく、最近の子どもったら。","ENG":"That's actually sort of freaky. Do kids these days have no common sense?","TWN":"喂，你覺得那正常嗎？現在的小孩子都這麼沒有常識嗎？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"아무튼 릴리 신경만 건드리지 않게 조심해. 걔 지금 엄청 히스테릭 상태야.","JPN":"とにかく、リリーの神経を刺激しないように気を付けて。あの子、今めちゃくちゃヒステリックな状態なの。","ENG":"Anyway, just try not to annoy Lily. She's super touchy right now.","TWN":"反正不要惹到莉莉，她現在可是很暴躁。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"알겠슴다!","JPN":"了解っす！","ENG":"Understood, ma'am!","TWN":"知道了！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L36_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"그런데 리코리스님, 왜 이렇게 모네를 챙겨 주심까?","JPN":"でもリコリス様、どうしてモネにこんなに気遣ってくれるんっすか？","ENG":"By the way, why are you so kind to Mone, ma'am?","TWN":"不過，莉克麗絲大人，你為什麼對莫妮這麼好啦？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"그야 나도 여러 가지 사정 때문에 맨션에 와서 이러고 있는 처지거든.","JPN":"まあ、私も色々と事情があってマンションに所属しているわけでね。","ENG":"Well, I have a long and complicated history behind why I'm at the Mansion myself.","TWN":"因為我也是因各種緣由才不得不來到了曼森。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"에휴, 내 신세......","JPN":"もうね、疲れちゃうわ……","ENG":"Ugh, it sucks to be me...","TWN":"唉，我的命好苦啊……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"그럼 모네에게 좋은 생각이 있슴다!","JPN":"ではモネに良い考えがあるっす！","ENG":"Then I've got a great idea, ma'am!","TWN":"莫妮想到了一個好辦法啦！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L40_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"네 머리에서 딱히 좋은 생각이 나올 거 같진 않은데?","JPN":"その頭から良い考えが出てくるとは思えないけど？","ENG":"You? You're the last person I'd think would offer any great ideas.","TWN":"你的小腦袋瓜能想到什麼好辦法？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L42_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"일단 들어 보시지 말임다!","JPN":"とりあえず聞いてほしいっす！","ENG":"Why don't you hear me out first?","TWN":"您先聽我說啦！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"저희는 모네랑 리코리스님 두 명이고 릴리님은 한 명이지 않슴까.","JPN":"ここにはモネとリコリス様で二人で、リリー様は一人じゃないっすか。","ENG":"There're two of us, and there's only one of Ms. Lily.","TWN":"莫妮和莉克麗絲大人是兩個人，但莉莉大人只是一個人啦。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"릴리님이 방심한 사이에 살금살금 다가가서","JPN":"リリー様が油断している隙を狙って、こっそり近づいて……","ENG":"We could sneak up behind her when she's lowered her guard and...","TWN":"所以我們可以趁莉莉大人放鬆警惕的時候偷偷地"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":" 왁!","JPN":"わっ！！","ENG":" Boo!","TWN":"哇！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"왁?","JPN":"わっ？？","ENG":"Boo?","TWN":"哇？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"와아아악?!","JPN":"わーーっ！？","ENG":"Eeeek?!","TWN":"哇啊啊啊？！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_WIND2"},{"id":"L50_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"너 언제 들어왔어?! 인기척이라도 내야 할 거 아냐!","JPN":"い、いつ戻ったの！？　帰って来たなら一言ぐらい言ってよ！","ENG":"When did you sneak in? At least make some sound when you're around!","TWN":"你什麼時候進來的？！一點動靜都沒有！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L2_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"마스터의 침실을 정리하러 드나들어야 하는 사람이 기척을 내고 돌아다닐 순 없죠.","JPN":"マスターの寝室を任された者として、音を立てて行動するわけにはいきません。","ENG":"A good bed maid should never make her presence known, lest she bother the Master in the comfort of her bedroom.","TWN":"要為主人整理床鋪的女僕是不能發出任何聲響的。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"그보다 저 꼬마랑 뭘 하고 있었나요? 무척 화기애애하게 떠드는 소리가 들리더군요?","JPN":"それより、あの子どもとずいぶん盛り上がっていたようですね。話し声が外まで聞こえていましたよ。","ENG":"In any case, what were you doing with the child? I heard you two chattering most gleefully.","TWN":"你跟這個小孩子說什麼呢？說的挺高興的。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"시, 심문의 기본은 가까워지기인 거 몰라?","JPN":"じ、尋問の基本はまず信頼を得るところからでしょ！","ENG":"D-don't you know bonding with your captive is the first step in any successful interrogation?","TWN":"拷、拷問的基本就是了解對方，你不知道嗎？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L7_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"내 요리를 더 먹기 싫으면 베로니카에 대해 아는 대로 불라고 했지.","JPN":"私の料理をこれ以上食べたくないなら、ベロニカについてすべて話せと言ったの。","ENG":"I told her she'd better tell me everything she knows about Veronica if she doesn't want to eat any more of my cooking.","TWN":"我跟她說，如果不想吃我的料理，就趕緊交代關於貝洛妮卡的事。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"그랬더니 순순히 털어 놓더라고.","JPN":"そうしたら大人しく吐き出したわ。","ENG":"So she fessed up.","TWN":"然後她就乖乖地說出來了。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L10_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"왜, 왜 그렇게 째려 봐?","JPN":"な、なによ。そんなに睨んで。","ENG":"W-why are you glaring at me like that?","TWN":"你、你幹嘛瞪我？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L11_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"이상한 소스에 집착하는 당신답지 않게 무척 효율적이군요.","JPN":"変なソースに執着するあなたらしくない、とても効率的な方法ですね。","ENG":"That was surprisingly efficient of you... for someone who obsesses over the strangest sauces.","TWN":"我以為你只會做一些奇怪的醬汁，沒想到辦事還挺有效率。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"고문도 괜찮다고 했지만 가장 비인도적인 짓부터 할 줄은 몰랐어요.","JPN":"拷問してもよいとは言いましたが、そこまで非人道的なやり方を使うとは思いませんでした。","ENG":"I said you may torture her, but I didn't expect you to resort to your cruelest tactic right away.","TWN":"雖然我同意你拷問，但沒想到你一上來就做這麼不人道的事。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"어디가 비인도적이야?! 다들 맛은 있다고 해 준다고!","JPN":"どこが非人道的なの！？　みんな味は美味しいと言ってくれるのに！","ENG":"What's so cruel about this? Everyone tells me it's pretty good!","TWN":"哪裡不人道了？！大家都說很好吃！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"저한테도 말해 보세요. 꼬맹이.","JPN":"私にも教えてください、おチビちゃん。","ENG":"Tell me what you told her, kid.","TWN":"給我也說說吧，小不點。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"넵?","JPN":"はいっ？","ENG":"Huh?","TWN":"啊？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"그 배신자에 대해서 말입니다.","JPN":"あの裏切り者についてです。","ENG":"About the traitor, I mean.","TWN":"關於那個叛徒。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"맨션을 등지고 혼자 사라진 뒤로 얼마나 속 편하게 살았는지 궁금하긴 하네요.","JPN":"マンションに背いて一人で消えた後どれぐらい気楽に暮らしていたのか、多少は気になります。","ENG":"I'd like to know how shamelessly comfortable she's been after she betrayed the Mansion.","TWN":"我倒是好奇，她背叛曼森後過的有多好。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"대답하지 않겠다면 평생 동안 지하실에 가둬 놓고 리코리스가 만든 요리만 줄 겁니다.","JPN":"答えないなら、一生真っ暗な地下室に閉じ込めてリコリスが作った料理だけを食べさせます。","ENG":"If you don't talk, I'll lock you up in the basement and feed you Lycoris's cooking for the rest of your life.","TWN":"如果你不說，我就把你關在地下室一輩子，然後天天讓你吃莉克麗絲的料理。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"흐, 흥. 말이 그렇다는 거지, 설마 그거만 갖고 됐겠냐?","JPN":"ふん！　それはむしろご褒美なんじゃないの？","ENG":"Oh come on, she's not going to break from that!","TWN":"哼，哼。就是說說而已，她怎麼可能會被這個嚇到。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L25_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"하나도 안 빼 놓고 말씀드리겠슴다~!","JPN":"ぜ、全部話すっすよ！","ENG":"I'll tell you everything, ma'am!","TWN":"我會全部告訴你的啦～！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};